SELECT * FROM (
    SELECT ROWNUM AS rnum, subquery.* FROM (
        SELECT 
            user_number, user_id, user_name, user_nickname, user_phone, user_email
        FROM ddd_user
        WHERE user_type = 'C'
        ORDER BY user_number DESC
    ) subquery
) 
